/* == EXEMPLE =======================================
 * AIO write basique avec attente par suspension
 * aio_suspend bloque jusqu'à complétion
 * ================================================= */
void example_aio(void) {
    char p[] = "/tmp/kf_ex_aio_XXXXXX";
    int fd = mkstemp(p); if (fd == -1) return; unlink(p);
    char buf[] = "test";
    struct aiocb cb;
    memset(&cb, 0, sizeof(cb));
    cb.aio_fildes = fd; cb.aio_buf = buf;
    cb.aio_nbytes = 4; cb.aio_offset = 0;
    aio_write(&cb);
    const struct aiocb *list[] = {&cb};
    aio_suspend(list, 1, NULL); /* bloque */
    printf("example: wrote %zd\n", aio_return(&cb));
    close(fd);
}
